/* --- Workspace (70/30 split) --- */
.workspace {
  display: grid;
  grid-template-columns: 1fr 280px;
  gap: 16px;
  padding: 0 24px 24px;
  flex: 1;
}

.main-panel {
  display: flex;
  flex-direction: column;
  min-height: 0;
}

.sidebar {
  display: flex;
  flex-direction: column;
  gap: 16px;
}

/* --- View Tabs --- */
.view-tabs {
  display: flex;
  gap: 0;
  margin-bottom: 16px;
  border-bottom: 1px solid var(--border);
}

.view-tab {
  background: none;
  border: none;
  padding: 10px 20px;
  font-family: var(--font-ui);
  font-size: 13px;
  font-weight: 600;
  color: var(--text-muted);
  cursor: pointer;
  border-bottom: 2.5px solid transparent;
  transition: color var(--transition), border-color var(--transition);
}

.view-tab:hover {
  color: var(--text-bright);
}

.view-tab.active {
  color: var(--gold);
  border-bottom-color: var(--gold);
}

/* --- Logs View --- */
.logs-view {
  flex: 1;
  display: flex;
  flex-direction: column;
  min-height: 0;
}

.log-toolbar {
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 10px 16px;
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: var(--radius-md) var(--radius-md) 0 0;
}

.level-filters {
  display: flex;
  gap: 0;
  border: 1px solid var(--border);
  border-radius: var(--radius-xs);
  overflow: hidden;
}

.filter-btn {
  background: var(--bg-input);
  border: none;
  padding: 5px 12px;
  font-family: var(--font-ui);
  font-size: 11px;
  font-weight: 600;
  color: var(--text-muted);
  cursor: pointer;
  transition: all var(--transition);
}
